var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"꼬맹이, 아까부터 왜 그렇게 조용해?","JPN":"なあ、さっきからやけに静かじゃないか。","ENG":"Why are you so quiet, kid?","TWN":"小鬼，你怎麼一直不說話？"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"나한테 할 말이 많지 않아?","JPN":"何か言いたいことがあるんじゃないのか？","ENG":"Don't you have something to say to me?","TWN":"你不是有很多話要對我說嗎？"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"그게...... 리타 언니는 제가 떠들면 싫어하니까요.","JPN":"それは……リタお姉ちゃんは私がうるさくおしゃべりすると嫌がるから……","ENG":"Well... You don't like it when I get chatty.","TWN":"那個……因為麗塔姐姐不喜歡我吵鬧嘛。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"언제는 내 말 듣고 얌전히 있던 것처럼 말하는군.","JPN":"いつもは私に言われたとおり大人しくしているような言い方だな。","ENG":"Since when did that stop you?","TWN":"說的好像你之前很聽話一樣。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"말해. 뭐가 문제야.","JPN":"さっさと言え。何が問題だ？","ENG":"Go ahead. What's bothering you?","TWN":"說吧，有什麼問題。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"아뇨. 문제 같은 거 없어요.","JPN":"いいえ。問題なんかありませんよ。","ENG":"Nothing. It's nothing, really.","TWN":"沒有，沒有問題。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"저는 그냥 리타 언니 소유물이니까...... 앞으로 얌전히 굴려고......","JPN":"私はお姉ちゃんの所有物にすぎないから……これから大人しくしてようと……","ENG":"Since I'm your property... I'm just going to be nice and quiet from now on...","TWN":"我只是麗塔姐姐的抵押品……以後我會老老實實的……"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"SS_SHADOW_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"어, 언니? 왜 그래요, 갑자기......?","JPN":"リ、リタお姉ちゃん？　どうしたんですか、急に……？","ENG":"R-Rita? What's wrong?","TWN":"姐、姐姐？你、你怎麼了……？"},"stage":{"bg":"SS_SHADOW_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"그래. 말 잘했어.","JPN":"そうだな。よく言ってくれた。","ENG":"Right. Well said.","TWN":"嗯，你說得很好。"},"stage":{"bg":"SS_SHADOW_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"난 네 부모들이 고용한 베이비시터가 아냐. 네 소유주지.","JPN":"私はお前の親に雇われたベビーシッターじゃない。お前の所有者なんだ。","ENG":"I'm not some babysitter your parents hired. I'm your owner.","TWN":"我不是你父母雇傭的保姆，而是你的主人。"},"stage":{"bg":"SS_SHADOW_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"그런데 넌 내 마음대로 될 때가 없어.","JPN":"なのにお前は私の思い通りになる時がない。","ENG":"But you never do as I say.","TWN":"但你很不聽話。"},"stage":{"bg":"SS_SHADOW_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"잠깐 눈을 떼면 멋대로 위험에 빠지질 않나, 틈만 나면 다쳐서 오질 않나......","JPN":"少し目を離すと勝手に危険なことに巻き込まれるし、隙あれば怪我をして……","ENG":"The moment I take my eyes off of you, you get yourself into danger, always getting yourself hurt.","TWN":"一不留神就陷入危險，動不動就受傷……"},"stage":{"bg":"SS_SHADOW_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"그러고도 화를 안 내길 바라는 게 웃기지.","JPN":"なのに、怒られたくないって？","ENG":"How am I supposed to not get angry at you?","TWN":"你這樣還期望我能夠不生氣嗎？"},"stage":{"bg":"SS_SHADOW_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"SS_SHADOW_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"넌 나 따위 안중에도 없어. 그 빌어먹을 집구석만 생각하기 바쁘니까.","JPN":"お前は私のことちっとも考えてないだろ。自分の家族のことばっかりで。","ENG":"You don't give a darn about me. All you care about is that hopeless family of yours.","TWN":"你根本不把我放在眼裡。因為你一心只想著你那個家。"},"stage":{"bg":"SS_SHADOW_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"돌아가고 싶은 거지? 네 부모들한테?","JPN":"帰りたいんだろ？　お前の親のところに。","ENG":"You want to go back to them? Back to your parents?","TWN":"你想回去是吧？回到你父母身邊？"},"stage":{"bg":"SS_SHADOW_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"그건......","JPN":"それは……","ENG":"Well...","TWN":"這……"},"stage":{"bg":"SS_SHADOW_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"빚 갚겠다는 말도 거짓말이겠지.","JPN":"借金を返すっていうのも嘘だろ。","ENG":"I bet all that talk of paying back the debt is a big fat lie.","TWN":"說要還債也是騙人的吧。"},"stage":{"bg":"SS_SHADOW_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"차라리 내 성질을 긁어서 쫓겨나려고 하는 거라면 믿겠어.","JPN":"むしろ、わざと私の機嫌を損ねて追い出されようとしているという方が信じられる。","ENG":"It'd be more plausible if you said you're trying to annoy me into getting rid of you.","TWN":"還不如說故意惹火我，然後被我趕出去，這我倒是相信。"},"stage":{"bg":"SS_SHADOW_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"언니, 전...... 엄마 아빤......","JPN":"リタお姉ちゃん、私は……お母さんとお父さんのことは……","ENG":"Rita, I... My parents...","TWN":"姐姐，我的……爸爸，媽媽……"},"stage":{"bg":"SS_SHADOW_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"잘 들어, 꼬맹이. 이 기회에 확실하게 말해 줄게.","JPN":"よく聞け、ガキ。いい機会だからはっきり言ってやるよ。","ENG":"Listen, kid. Let me set one thing straight, once and for all.","TWN":"聽好了，小鬼。我今天就清楚地告訴你。"},"stage":{"bg":"SS_SHADOW_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"그 작자들, 그러니까 네 부모들은......","JPN":"あいつら、つまりお前の親どもは……","ENG":"Those dirtbags of parents you've got are...","TWN":"那些傢伙，就是你的父母……"},"stage":{"bg":"SS_SHADOW_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"SS_SHADOW_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"SS_SHADOW_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"하아......","JPN":"はあ……","ENG":"*Sigh*","TWN":"哈啊……"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"관두자. 나도 참, 어린애 상대로 무슨 말을 하자는 건지.","JPN":"やめた。まったく、ガキ相手に何言おうとしてるんだか。","ENG":"Forget it. What am I doing, trying to tell a kid like you that sort of stuff...","TWN":"算了。我也真是，跟小孩子說這些做什麼呢。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"눈 떠. 꼬맹이.","JPN":"目を開けろ、ガキ。","ENG":"Open your eyes, kid.","TWN":"睜開眼睛，小鬼。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"......정말 떠도 돼요? 안 잡아먹을 거죠?","JPN":"……本当に開けていいんですか？　私、食べられないですよね？","ENG":"Can I, really? You're not going to eat me alive?","TWN":"……真的可以睜開嗎？不會吃掉我吧？"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"잡아먹긴 널 왜 잡아먹어.","JPN":"食うって？　お前を？","ENG":"Of course not. Why would you even say that?","TWN":"我幹嘛要吃掉你。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"그렇지만 방금 전에 리타 언니는 엄청 무서웠는걸요! 잡아먹히는 줄 알았어요!","JPN":"さっきのリタお姉ちゃん、すごく怖かったんです！　食べられちゃいそうでしたよ！","ENG":"But you looked super scary just now! I thought you'd devour me!","TWN":"可是剛剛麗塔姐姐超級嚇人！我以為我要被吃掉了呢！"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"그래도 방금 얘기를 듣고 언니의 진심을 깨달았어요!","JPN":"でも今の話を聞いて、リタお姉ちゃんの本心がわかりました！","ENG":"Still, I came to realize how you feel after what you just told me.","TWN":"但剛剛聽到姐姐的話，我明白了姐姐的真心！"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L43_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"제가 다른 사람들보다 언니를 더 소중하게 생각해 줬으면 하는 거죠?","JPN":"私が他の人よりもリタお姉ちゃんのことをもっと大事にしてほしいって思ってるんですね！？","ENG":"You wish I'd care for you more than others, right?","TWN":"你希望比起他人，我更應該珍惜姐姐對不對？"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L44_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"......너도 호라이즌처럼 사고회로가 고장났어?","JPN":"……お前もホライズンみたいに思考回路がぶっ壊れたのか？","ENG":"Did something go wrong with your circuitry like Horizon?","TWN":"……你也跟地平線一樣腦子出問題嗎？"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"무슨 과정을 거쳐야 그런 황당한 결론이 나오는지 모르겠군.","JPN":"何をどうすればそんなぶっ飛んだ結論にいたるのか不思議だな。","ENG":"I have no idea how you even reached that conclusion.","TWN":"真不知道你這荒唐的結論是怎麼得來的。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"느낌으로 알 수 있죠. 언니랑 세상에서 제일 가까운 사람은 저잖아요.","JPN":"気持ちが伝わるんです。リタお姉ちゃんと世界で一番仲がいい人は私でしょー？","ENG":"It's just a gut feeling. I'm the closest person to you in the world, after all.","TWN":"憑感覺就知道啊。因為我是世界上跟姐姐最親近的人。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"그런 거라면 걱정 마세요! 전 언니를 따라다닐 때가 제일 행복하거든요!","JPN":"そんなことなら心配しないでください！　私はリタお姉ちゃんと一緒にいる時が一番幸せなんです！","ENG":"Well, you don't have to worry about that! Nothing makes me happier than following you around!","TWN":"所以不用擔心哦！我跟著姐姐的時候是最幸福的！"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"하여튼......","JPN":"これは参ったな……","ENG":"You're incurable, aren't you?","TWN":"總之……"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"내 옆자리가 탐나면 호라이즌부터 이기고 와.","JPN":"私の相棒の席が欲しいならホライズンに勝ってから出直せ。","ENG":"You'd better beat Horizon first if you want to stick by my side.","TWN":"想要跟我一起的話，先贏了地平線再說。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"에이, 대표님은 제가 부전승해도 상관없다고 하셨어요.","JPN":"えー、代表は私なら不戦勝でも構わないって言ってましたよ？","ENG":"Oh, the boss said she wouldn't mind if I took her spot.","TWN":"哎呀，BOSS說了，即使我不戰而勝也沒關係。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"......그 고철은 꼭 필요할 때 도움이 안 되는군.","JPN":"……あの鉄くずはいざという時まったく役に立たないな。","ENG":"That piece of junk never helps, does she...","TWN":"……那個廢鐵真是每次需要他的時候就會掉鏈子。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"이제부터 절대 내 옆에서 떨어지지 마. 마지막 경고야.","JPN":"これからは絶対に私のそばから離れるな。これが最後の警告だ。","ENG":"Don't you ever leave my side from now on. This is your final warning.","TWN":"現在開始絕對不能離開我的視線，這是最後的警告。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"넹!!","JPN":"はいっ！！","ENG":"Oki, ma'am!","TWN":"是！！"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};